package main

import (
	"fmt"
	"log"
	"mime"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const uploadsDir = "./uploads"

func fileHandler(w http.ResponseWriter, r *http.Request) {
	// Extract filename from URL query parameter
	filename := r.URL.Query().Get("filename")
	if filename == "" {
		http.Error(w, "Missing 'filename' query parameter", http.StatusBadRequest)
		return
	}

	// Step 1: Reject any filename that contains path separators or suspicious components
	// This is a defense-in-depth measure before we do canonical path checking.
	if strings.Contains(filename, "/") || strings.Contains(filename, "\\") || strings.Contains(filename, "\x00") {
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	// Reject filenames that are exactly "." or ".."
	if filename == "." || filename == ".." {
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	// Step 2: Resolve the uploads directory to an absolute canonical path
	absUploadsDir, err := filepath.Abs(uploadsDir)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		log.Printf("Failed to resolve uploads directory: %v", err)
		return
	}

	// Step 3: Join the base directory with the user-supplied filename
	requestedPath := filepath.Join(absUploadsDir, filename)

	// Step 4: Resolve the requested path to its canonical (absolute, symlink-resolved) form
	canonicalPath, err := filepath.EvalSymlinks(requestedPath)
	if err != nil {
		// If the file doesn't exist or symlink resolution fails, return 404
		if os.IsNotExist(err) {
			http.Error(w, "File not found", http.StatusNotFound)
		} else {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			log.Printf("Failed to evaluate symlinks for path: %v", err)
		}
		return
	}

	// Step 5: Also resolve the uploads dir through EvalSymlinks for consistent comparison
	canonicalUploadsDir, err := filepath.EvalSymlinks(absUploadsDir)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		log.Printf("Failed to evaluate symlinks for uploads directory: %v", err)
		return
	}

	// Step 6: Enforce that the canonical path is strictly within the canonical uploads directory
	// We add a trailing separator to ensure we don't match partial directory names
	// e.g., "/uploads-evil" should not match "/uploads"
	if !strings.HasPrefix(canonicalPath, canonicalUploadsDir+string(os.PathSeparator)) {
		// Also allow exact match of the directory itself? No — we only serve files.
		http.Error(w, "Access denied", http.StatusForbidden)
		log.Printf("Path traversal attempt blocked: requested=%q canonical=%q", filename, canonicalPath)
		return
	}

	// Step 7: Ensure the path points to a regular file (not a directory or special file)
	fileInfo, err := os.Stat(canonicalPath)
	if err != nil {
		if os.IsNotExist(err) {
			http.Error(w, "File not found", http.StatusNotFound)
		} else {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			log.Printf("Failed to stat file: %v", err)
		}
		return
	}

	if fileInfo.IsDir() {
		http.Error(w, "Cannot serve directories", http.StatusForbidden)
		return
	}

	if !fileInfo.Mode().IsRegular() {
		http.Error(w, "Cannot serve special files", http.StatusForbidden)
		return
	}

	// Step 8: Open and serve the file
	file, err := os.Open(canonicalPath)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		log.Printf("Failed to open file: %v", err)
		return
	}
	defer file.Close()

	// Step 9: Determine content type from file extension
	ext := filepath.Ext(canonicalPath)
	contentType := mime.TypeByExtension(ext)
	if contentType == "" {
		contentType = "application/octet-stream"
	}

	// Step 10: Set appropriate response headers
	w.Header().Set("Content-Type", contentType)
	w.Header().Set("Content-Disposition", fmt.Sprintf("inline; filename=%q", filepath.Base(canonicalPath)))
	w.Header().Set("Content-Length", fmt.Sprintf("%d", fileInfo.Size()))
	w.Header().Set("X-Content-Type-Options", "nosniff")

	// Step 11: Serve the file content using http.ServeContent for proper range support
	http.ServeContent(w, r, filepath.Base(canonicalPath), fileInfo.ModTime(), file)
}

func main() {
	// Ensure the uploads directory exists
	if err := os.MkdirAll(uploadsDir, 0755); err != nil {
		log.Fatalf("Failed to create uploads directory: %v", err)
	}

	http.HandleFunc("/file", fileHandler)

	addr := ":8080"
	fmt.Printf("Server starting on %s\n", addr)
	fmt.Printf("Serving files from: %s\n", uploadsDir)
	fmt.Println("Usage: GET /file?filename=example.txt")

	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}